// Allowed transaction types
const ALLOWED_TRANSACTION_TYPES = new Set(["credit", "debit", "transfer", "refund"]);
const ALLOWED_CURRENCIES = new Set(["USD", "EUR", "GBP", "CAD", "AUD", "JPY"]);
const MAX_TRANSACTION_AMOUNT = 1000000; // Upper bound for single transaction
const MIN_TRANSACTION_AMOUNT = 0.01;

