/**
 * Validate and sanitize transaction data from SQS message.
 * Never trust message content blindly - validate all fields.
 */
function validateAndSanitizeTransaction(messageBody) {
  let parsed;
  try {
    parsed = JSON.parse(messageBody);
  } catch (err) {
    throw new Error("Invalid JSON in message body");
  }

  const { transactionId, accountId, amount, currency, type, description, timestamp } = parsed;

  // Validate transactionId - must be a valid UUID
  if (!transactionId || typeof transactionId !== "string") {
    throw new Error("Missing or invalid transactionId");
  }
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
  if (!uuidRegex.test(transactionId)) {
    throw new Error("transactionId must be a valid UUID");
  }

  // Validate accountId - alphanumeric with hyphens, reasonable length
  if (!accountId || typeof accountId !== "string") {
    throw new Error("Missing or invalid accountId");
  }
  const accountIdRegex = /^[a-zA-Z0-9-]{1,64}$/;
  if (!accountIdRegex.test(accountId)) {
    throw new Error("accountId contains invalid characters or exceeds length limit");
  }

  // Validate amount - must be a finite positive number within bounds
  if (amount === undefined || amount === null || typeof amount !== "number") {
    throw new Error("Missing or invalid amount");
  }
  if (!Number.isFinite(amount)) {
    throw new Error("Amount must be a finite number");
  }
  if (amount < MIN_TRANSACTION_AMOUNT || amount > MAX_TRANSACTION_AMOUNT) {
    throw new Error(`Amount must be between ${MIN_TRANSACTION_AMOUNT} and ${MAX_TRANSACTION_AMOUNT}`);
  }
  // Round to 2 decimal places to avoid floating point issues
  const sanitizedAmount = Math.round(amount * 100) / 100;

  // Validate currency
  if (!currency || typeof currency !== "string") {
    throw new Error("Missing or invalid currency");
  }
  const upperCurrency = currency.toUpperCase().trim();
  if (!ALLOWED_CURRENCIES.has(upperCurrency)) {
    throw new Error(`Unsupported currency: ${upperCurrency}`);
  }

  // Validate transaction type
  if (!type || typeof type !== "string") {
    throw new Error("Missing or invalid transaction type");
  }
  const lowerType = type.toLowerCase().trim();
  if (!ALLOWED_TRANSACTION_TYPES.has(lowerType)) {
    throw new Error(`Invalid transaction type: ${lowerType}`);
  }

  // Sanitize description - optional, limit length, strip control characters
  let sanitizedDescription = "";
  if (description !== undefined && description !== null) {
    if (typeof description !== "string") {
      throw new Error("Description must be a string");
    }
    // Remove control characters and limit length
    sanitizedDescription = description.replace(/[\x00-\x1F\x7F]/g, "").substring(0, 256).trim();
  }

  // Validate timestamp
  if (!timestamp || typeof timestamp !== "string") {
    throw new Error("Missing or invalid timestamp");
  }
  const parsedTimestamp = new Date(timestamp);
  if (isNaN(parsedTimestamp.getTime())) {
    throw new Error("Invalid timestamp format");
  }
  // Reject timestamps too far in the future or past (e.g., more than 24 hours)
  const now = Date.now();
  const twentyFourHoursMs = 24 * 60 * 60 * 1000;
  if (Math.abs(parsedTimestamp.getTime() - now) > twentyFourHoursMs) {
    throw new Error("Timestamp is too far from current time");
  }

  return {
    transactionId: transactionId.toLowerCase(),
    accountId,
    amount: sanitizedAmount,
    currency: upperCurrency,
    type: lowerType,
    description: sanitizedDescription,
    timestamp: parsedTimestamp.toISOString(),
  };
}

/**
 * Idempotency check - ensure we haven't already processed this message.
 * Critical for financial transactions to prevent duplicate processing.
 * Even if SQS "should only send once," at-least-once delivery is the guarantee.
 */
async function isMessageAlreadyProcessed(messageId, transactionId) {
  try {
    const result = await docClient.send(
      new GetCommand({
        TableName: PROCESSED_MESSAGES_TABLE,
        Key: { messageId },
        ProjectionExpression: "messageId, transactionId, processedAt",
      })
    );
    if (result.Item) {
      console.log(
        `Duplicate detected: messageId=${messageId}, transactionId=${transactionId}, ` +
        `originally processed at ${result.Item.processedAt}`
      );
      return true;
    }
    return false;
  } catch (err) {
    // If we can't verify idempotency, fail safe - do not process
    console.error(`Idempotency check failed for messageId=${messageId}:`, err.message);
    throw new Error("Unable to verify message idempotency - refusing to process");
  }
}

/**
 * Record that a message has been processed for idempotency tracking.
 * Uses a conditional write to prevent race conditions.
 */
async function recordProcessedMessage(messageId, transactionId) {
  const ttlSeconds = Math.floor(Date.now() / 1000) + 7 * 24 * 60 * 60; // 7 day TTL
  try {
    await docClient.send(
      new UpdateCommand({
        TableName: PROCESSED_MESSAGES_TABLE,
        Key: { messageId },
        UpdateExpression: "SET transactionId = :tid, processedAt = :pat, #ttl = :ttl",
        ConditionExpression: "attribute_not_exists(messageId)",
        ExpressionAttributeNames: { "#ttl": "ttl" },
        ExpressionAttributeValues: {
          ":tid": transactionId,
          ":pat": new Date().toISOString(),
          ":ttl": ttlSeconds,
        },
      })
    );
  } catch (err) {
    if (err.name === "ConditionalCheckFailedException") {
      console.log(`Race condition caught: messageId=${messageId} was already recorded`);
      throw new Error("Duplicate processing detected via conditional write");
    }
    throw err;
  }
}

/**
 * Process a single validated transaction by updating the database.
 * Uses conditional expressions to ensure data integrity.
 */
async function processTransaction(transaction) {
  const { transactionId, accountId, amount, currency, type, description, timestamp } = transaction;

  const now = new Date().toISOString();

  // Determine the effective amount change based on transaction type
  let amountChange;
  switch (type) {
    case "credit":
    case "refund":
      amountChange = amount;
      break;
    case "debit":
      amountChange = -amount;
      break;
    case "transfer":
      amountChange = -amount; // Outgoing transfer
      break;
    default:
      throw new Error(`Unhandled transaction type: ${type}`);
  }

  // Store the transaction record
  await docClient.send(
    new UpdateCommand({
      TableName: TRANSACTIONS_TABLE,
      Key: { transactionId },
      UpdateExpression:
        "SET accountId = :aid, amount = :amt, currency = :cur, transactionType = :typ, " +
        "description = :desc, transactionTimestamp = :ts, processedAt = :pat, " +
        "amountChange = :ac, #status = :status",
      ConditionExpression: "attribute_not_exists(transactionId)",
      ExpressionAttributeNames: {
        "#status": "status",
      },
      ExpressionAttributeValues: {
        ":aid": accountId,
        ":amt": amount,
        ":cur": currency,
        ":typ": type,
        ":desc": description,
        ":ts": timestamp,
        ":pat": now,
        ":ac": amountChange,
        ":status": "processed",
      },
    })
  );

  console.log(
    `Transaction processed: id=${transactionId}, account=${accountId}, ` +
    `type=${type}, amount=${amount} ${currency}, change=${amountChange}`
  );
}

